var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"잘 오셨습니다.","JPN":"ようこそおいでくださいました。","ENG":"Welcome.","TWN":"歡迎你們。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"기다리느라 꽤 지루했어요.","JPN":"待ちくたびれてしまいましたよ。","ENG":"I must admit, I was getting rather bored waiting for you.","TWN":"我等得都快要不耐煩了呢。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신! 나래를 어떻게 했어?!","JPN":"あんた！　ナルミをどうしたの！？","ENG":"You! What have you done with Narae?","TWN":"喂！你把娜拉怎麼樣了？！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"물러서, 신입. 내가 이야기하지.","JPN":"下がれ新人。私から話そう。","ENG":"Stand down, rookie. I'll take it from here.","TWN":"退下，新人。讓我來說。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만.......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"말했지. 저 녀석은 내 용건이다.","JPN":"言ったよな。私はあいつに用があるんだ。","ENG":"I told you. He’s my business to settle.","TWN":"我說過了，那小子是我要處理的事情。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"친구를 구하고 싶다고 했지? 넌 네 용건에 집중해.","JPN":"友達を助けたいと言ってたろう？　お前は自分の用事に集中するんだ。","ENG":"Didn’t you say you wanted to save your friend? Just focus on your task at hand.","TWN":"妳想要找妳朋友對吧？那就專心去辦妳的事。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알았어.","JPN":"わかった。","ENG":"Fine.","TWN":"知道了。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나유빈.","JPN":"イチノセ・カオル。","ENG":"Na Yubin.","TWN":"羅瑜斌。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"환영인사는 마음에 드셨나요? 스승님.","JPN":"歓迎のあいさつは喜んで頂けましたか？　師匠。","ENG":"So, did you like my welcome party, Master?","TWN":"您對我們的歡迎還滿意嗎？ 師父。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그다지. 사실 조금 시시했어.","JPN":"いや、正直少し退屈したぞ。","ENG":"Not really. It was pretty lame, actually.","TWN":"不怎麼樣。說實話有點無聊。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 알던 예전의 너라면 이것보다는 나을 줄 알았는데.","JPN":"私の知っているお前なら、これよりはマシだと思ったのにな。","ENG":"I would’ve expected more from the Yubin I used to know.","TWN":"如果是以前我認識的你，應該會做得更好才對。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 다음번에는 기대에 어긋나지 않도록 노력해 보죠.","JPN":"あははっ、次は期待外れにならないようにがんばりますね。","ENG":"Haha, I’ll try not to disappoint next time.","TWN":"哈哈，那為了不辜負師父的期望，我下次就多加努力吧。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"정말 살아 있었군.","JPN":"本当に生きていたんだな。","ENG":"So you really did survive after all.","TWN":"你真的活下來了。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"운이 좋았죠. 다 스승님의 엄한 지도 덕분이라고 생각하고 있습니다.","JPN":"運が良かったです。　すべて師匠の厳しいご指導のおかげだと思います。","ENG":"I got lucky. I owe it all to your stern teaching, Master.","TWN":"運氣好而已。我想這大部分都歸功於師父嚴厲的指導。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래? 도움이 되었다니 다행이군.","JPN":"そうか？　役に立ったなら良かった。","ENG":"Is that so? I’m glad I could be of help.","TWN":"是嗎？能幫上你的忙，我很高興呢。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래서, 굳이 여기로 부른 이유가 뭐지?","JPN":"で、わざわざここに呼んだ理由は何だ？","ENG":"So, why did you make me come all the way out here?","TWN":"所以，你為什麼非要把我叫到這裡？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"오랜만에 만난 회포를 풀기에는 더 괜찮은 곳도 많을 텐데.","JPN":"長年の積もった話をするなら、もっと良い場所もあっただろうに。","ENG":"I’m sure there are more pleasant venues where we could catch up.","TWN":"想要一敘許久不見的思念之情，應該有其他更好的地方吧。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"커피숍이라든가.","JPN":"カフェとかな。","ENG":"Like a coffee shop, for instance.","TWN":"比如說咖啡店之類的。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"글쎄요.","JPN":"どうでしょう。","ENG":"You think so?","TWN":"是呢……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"좀 황량하긴 하지만 여기도 나쁘지 않지 않나요?","JPN":"少し殺風景ではありますが、ここも悪くないんじゃないですか？","ENG":"I mean, this place sure could use a little more decoration, but it’s not so bad, is it?","TWN":"不過這裡雖然有點荒涼，但也不算太差吧？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"모든 게 끝나고, 또 시작된 장소니까요.","JPN":"すべてが終わり、また始まった場所ですからね。","ENG":"After all, this is where everything ended... and began.","TWN":"因為這是一切結束，然後又開始的地方。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 이곳을 좋아해요.","JPN":"僕はここが気に入ってます。","ENG":"I like this place.","TWN":"我喜歡這裡。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"가끔 이곳에 와서 옛 생각을 떠올리면 마음이 차분해지거든요.","JPN":"時々ここに来て昔のことを思い出すと、心が落ち着くんですよ。","ENG":"Sometimes I come here to reminisce about the good old days... It puts my mind at ease.","TWN":"我有時會來這裡。我只要一想起過去，內心就會變得很平靜。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......안타깝지만 난 나쁜 기억을 되새김질하면서 즐거워하는 악취미는 없어.","JPN":"……残念だが、私には辛い記憶をわざわざ思い起こして楽しむような悪趣味はない。","ENG":"Regrettably I don’t share your penchant for recollecting terrible experiences.","TWN":"……很遺憾，我可沒有想起不愉快的回憶就會高興的糟糕興趣。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"빙빙 돌리지 말고 본론을 말해.","JPN":"遠回しにせず、本題を言え。","ENG":"Cut to the chase already.","TWN":"別拐彎抹角了，讓我們進入正題吧。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대체 뭘 꾸미고 있는 거냐, 나유빈. 리플레이서와는 또 무슨 관계고?","JPN":"イチノセ、いったい何を企んでる。リプレイサーとはどんな関係だ？","ENG":"What are you plotting, Yubin? And how are you involved with the Replacer?","TWN":"你到底有什麼企圖，羅瑜斌。你和克隆集團又是什麼關係？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연에게 전해 들었다. 그 녀석을 구해 준 게 너라고 하더군.","JPN":"カナミから聞いたよ。お前があいつを助けたんだってな。","ENG":"Sooyeon told me. She says you saved her.","TWN":"我從李秀妍那裡聽說了，救了她的人是你。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그동안 사실을 숨긴 건 괘씸하지만, 나도 큰소리 칠 입장은 아니니까 그건 고맙다고 말해 두지.","JPN":"これまで隠していたのは許しがたいが、私が言えた立場ではないし、この件については礼を言う。","ENG":"As peeved I am for being kept in the dark, I guess I’m in no place to lecture. So thanks for that, at least.","TWN":"雖然你隱瞞了事實很可惡，但對此我也不能說什麼，所以我只能向你說聲謝謝。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"혹시 만약 그때의 일로 내게 할 말이 있다면 얼마든지 들어 줄.......","JPN":"もしあの時のことで私に言いたいことがあるなら、いくらでも聞いてや……","ENG":"Now, if there's anything else you wanted to talk to me about from that day, I’m ready to hear you out...","TWN":"如果你對當時的事情有什麼話要說的話，不管多少我都會聽的……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 이것 참.","JPN":"ははっ、まいったな……","ENG":"Haha, oh my.","TWN":"哈哈，這真是。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"예전 일을 아직 걱정하고 있다면 그러실 필요 없어요.","JPN":"昔のことを心配しているなら、そんな必要はありません。","ENG":"If you're still worried about the past, there’s no need for that.","TWN":"如果您還在擔心以前的事情的話，那實在沒有這個必要。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 스승님을 원망하는 마음은 전혀 없으니까요.","JPN":"僕には師匠を恨む気はまったくありませんから。","ENG":"I don’t hold any grudges against you, Master.","TWN":"因為我完全沒有怨恨師父的想法。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"오히려 현실을 직시하게 해 줘서 감사하다고 할까요?","JPN":"むしろ現実と向き合わせてくれて、ありがとうと言いたいところです。","ENG":"If anything, I’m grateful to you for helping open my eyes.","TWN":"您反而讓我面對現實，所以我應該要非常感謝您吧？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그게 무슨.......","JPN":"それはどういう……","ENG":"What the hell is that supposed to mean?","TWN":"這是什麼意思……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"자, 그러면 이 이야기는 여기까지 하도록 하죠.","JPN":"さあ、この話はここまでにしましょう。","ENG":"I think that’s enough of that for today.","TWN":"好了，那今天這個話題就聊到這裡吧。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저도 스승님과 더 길게 대화를 나누고 싶지만, 오늘의 주인공을 너무 기다리게 하는 것도 조금 곤란해서요.","JPN":"僕も師匠とじっくり話したいところですが、今日の主人公をこれ以上待たせるのも困りますしね。","ENG":"I'd love to stay and chat, but I can’t keep the main guest waiting much longer, you see.","TWN":"雖然我也想和師父多聊一會兒，但是讓今天的主角等太久也不太好呢。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"なっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"애초에 제가 이곳으로 초대한 건 스승님이 아니라 유미나 씨입니다.","JPN":"元を言えば、僕がここに招待したのは師匠ではなく、ヤナギ・ミナさんです。","ENG":"The person I invited here today is not you, Master, but Mina.","TWN":"畢竟我一開始邀請的就不是師父您，而是劉米娜小姐。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니 죄송하지만, 스승님은 저와 미나 씨의 용건이 끝날 때까지 방해하지 말아 주셨으면 좋겠군요.","JPN":"なので申し訳ありませんが、師匠は僕とミナさんの用件が終わるまで邪魔しないでもらいたいです。","ENG":"With all due respect, I’d appreciate it if you could stay out of the way until my business with Mina is done here.","TWN":"雖然很抱歉，但在我和劉米娜小姐把事情處理完之前，希望師父不要妨礙我們。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"무슨 헛소리를!","JPN":"たわけたことを抜かすな！","ENG":"How dare you!","TWN":"你在說什麼鬼話！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くっ！","ENG":"Hngh!","TWN":"唔！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"당신이 그 전설의 펜릴 전대장인가?","JPN":"お前があの伝説のフェンリル戦隊長？","ENG":"So are you the Commander of the Fenrir Division?","TWN":"妳就是那個傳說中的芬里爾戰隊的隊長嗎？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......어디서 그런 이야기를 들은 거지? 나유빈이 말해 줬나?","JPN":"……どこでそんな話を聞いた？　イチノセか？","ENG":"Who told you about that? Was it Yubin?","TWN":"……妳是從哪裡聽說呢？羅瑜斌嗎？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"......녹슬었군.","JPN":"……随分と衰えたものだ。","ENG":"You’ve grown rusty.","TWN":"妳變遲鈍了呢……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"실망이야.","JPN":"がっかりだよ。","ENG":"I’m disappointed.","TWN":"真令人失望。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"당신에 대한 소문이 절반만 사실이라고 해도 꽤나 흥미로운 상대였을 텐데.","JPN":"うわさが半分でも本当だったら、もっと戦いがいがあっただろうに。","ENG":"You would’ve been much more interesting to fight if you lived up to even half of what they say about you.","TWN":"要是關於妳的傳聞中，有一半是事實的話，那妳一定是個非常有趣的對手。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"이래서야 기대했던 내가 바보 같은걸.","JPN":"これでは期待していた自分が恥ずかしくなる。","ENG":"I guess I’m the fool for getting my hopes up.","TWN":"會對妳感到期待的我真是愚蠢啊。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 자식이...... 당장 비켜! 그렇지 않으면......!","JPN":"この野郎……今すぐどけ！　でなければ……！","ENG":"Why you little... Get out of my way... Or else!","TWN":"這傢伙……快滾開！不然的話……！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"대장이 용무를 마치기 전까지 당신은 여기서 한 발자국도 움직일 수 없어.","JPN":"隊長の用事が済むまで、お前はここから一歩も動けない。","ENG":"You’re not going anywhere until the Commander is done with his business.","TWN":"在隊長的事情處理完之前，妳就待在這裡，一步也不准動。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"그쪽의 꼬마도 마찬가지다.","JPN":"そこのチビもな。","ENG":"The same goes for your little sidekick.","TWN":"那邊那個小鬼也是。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"방해한다면 이번엔 팔 하나로 끝나지 않을 거다.","JPN":"邪魔するなら、今度は腕一本じゃ終わらせない。","ENG":"If you interfere again, you’ll have more than just your arm to worry about this time.","TWN":"你要是敢妨礙我們的話，這次可不會那麼輕易地就放過你。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"뭣하면 둘이 같이 덤벼도 좋아. 상대해 주지.","JPN":"何なら二人同時にかかってきてもいいぞ。相手してやる。","ENG":"You’re welcome to gang up on me if that helps. I can take it.","TWN":"不然你們兩個人一起上好了，我來當你們的對手。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......이런 건방진 소리는 정말 오랜만에 들어 보는군.","JPN":"……そんな生意気を聞いたのは実に久しぶりだ。","ENG":"It's been a while since I've met an opponent so sure of herself.","TWN":"……這種傲慢的發言，還真是很久沒聽到了。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 말솜씨만큼 실력이 받쳐 주는지 확인해 주지!","JPN":"その言葉通りの実力なのか、今すぐ確かめてやろうじゃないか！","ENG":"Fine. Let’s see if you're really as good as you say!","TWN":"那就讓我來看看，妳的實力有沒有和妳的嘴巴一樣厲害。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어떻게 인사를 해야 할지 모르겠군요.","JPN":"どのように挨拶すれば良いのか……","ENG":"I’m not sure what the proper greeting would be here.","TWN":"真是不知道該怎麼打招呼呢。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다? 아니면, 오랜만입니다?","JPN":"初めまして、それとも、お久しぶり、と言うべきですかね？","ENG":"Pleased to make your acquaintance? Or long time no see?","TWN":"要說初次見面？ 還是好久不見？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 그냥 반갑습니다 정도가 적당할 것 같네요.","JPN":"もっとシンプルに、会えて嬉しい、くらいが良さそうですね。","ENG":"Haha, I guess just “nice to meet you” would suffice.","TWN":"哈哈，說很高興見到妳看來最合適吧。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"반갑습니다. 유미나 씨.","JPN":"会えて嬉しいです、ヤナギ・ミナさん。","ENG":"Nice to meet you. Ms. Yoo Mina.","TWN":"很高興見到妳，劉米娜。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......당신!","JPN":"……あんた！","ENG":"You!","TWN":"……你！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇게 경계하지 마세요.","JPN":"そんなに警戒しないでください。","ENG":"No need to get so defensive now.","TWN":"請不要這麼戒備。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신에게 해를 끼칠 생각은 없으니까요.","JPN":"あなたに害を及ぼすつもりはないですから。","ENG":"I’m not going to hurt you.","TWN":"我並沒有危害妳的意思。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나래는? 나래는 어떻게 한 거야?","JPN":"ナルミは？　ナルミはどうなったの？","ENG":"Where’s Narae? What have you done to her?","TWN":"娜拉呢？娜拉怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 해치기라도 한 건......?","JPN":"まさかナルミに何かしたんじゃ……","ENG":"Did you hurt her, you bastard?","TWN":"你該不會傷害了她吧？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"걱정마세요. 미나 씨의 친구는 아주 멀쩡하니까요.","JPN":"心配いりませんよ。ミナさんの友達は、何ともないですから。","ENG":"Don't worry. Your friend is perfectly fine.","TWN":"別擔心，米娜小姐的朋友很平安。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 그분은 미나 씨를 죽이려고 했는데, 그래도 미나 씨는 그분을 친구라고 생각하는 것 같네요.","JPN":"しかし、あなたを殺そうとしたのに、それでもあの方を友達だと思ってるんですね。","ENG":"I’m surprised you still consider her a friend, seeing how she definitely tried to kill you.","TWN":"不過，她明明想要殺掉米娜小姐，但米娜小姐還是把她當成朋友呢。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건...... 분명...... 오해가 있었을 거야.","JPN":"あれは……きっと……何か誤解してるのよ。","ENG":"That’s... probably... just a misunderstanding.","TWN":"這……這一定是……有什麼誤會。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 놈들이 나래에게 무슨 수작을 부린 게 틀림없어!","JPN":"リプレイサーの奴らがナルミに何かしたに違いない！","ENG":"Those Replacer scumbags must’ve played some kind of trick on her!","TWN":"一定是克隆集團那些傢伙做了什麼好事！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대화를 해 보면...... 그래, 그러면 반드시 내가 알던 나래로 돌아올 거야!","JPN":"話をすれば……そう、そうすれば、きっと以前のナルミに戻るはずだ！","ENG":"If I could just talk to her... Yes, I’m sure she’d return to the Narae I know!","TWN":"只要能與娜拉談談……對，只要能和娜拉談談，她一定能變回我認識的那個娜拉！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하긴, 옛 인연이라는 건 누구에게나 떨쳐내기 어려운 족쇄이기 마련이죠.","JPN":"まあ、誰にとっても古い縁はいつまでも切れない鎖みたいなものですからね。","ENG":"Haha, the notion of old friends can prove to be an unbreakable tether for all of us.","TWN":"說起來，昔日緣分這種東西，是任何人都難以擺脫的枷鎖。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 스스로 기억하지 못하는 인연도 사람을 구속할 수 있을까요?","JPN":"ただ、自ら覚えていない縁も人を縛ることができるのでしょうか。","ENG":"But could the same be said of someone who can’t remember her own past?","TWN":"但如果是本人都已經不記得的緣分，那還能夠成為人的束縛嗎？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 궁금하네요.","JPN":"僕はそこが気になりますね。","ENG":"I’m curious to find out.","TWN":"我很好奇呢。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"멍청한 짓 하지 마! 나유빈!","JPN":"バカなことするな！　イチノセ！","ENG":"Don’t do anything stupid, Yubin!","TWN":"別做傻事，羅瑜斌！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석은 네가 생각하는 사람이 아니야!!","JPN":"そいつはお前が思うような人間じゃない！！","ENG":"She's not who you think she is!","TWN":"米娜不是你想像的那個人！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건 시험해 보면 알게 되겠죠.","JPN":"それは試してみればわかるでしょう。","ENG":"There’s only one way to find out.","TWN":"這個我試一下就知道了。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"내기할까요, 스승님?","JPN":"師匠、賭けてみますか？","ENG":"Care to bet on it, Master?","TWN":"要打個賭嗎，師父？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제가 이곳을 재회의 장소로 삼은 건 단지 추억 때문만은 아니거든요.","JPN":"私がここを再会の場所にしたのは、単に思い出のためだけではないんです。","ENG":"I didn’t choose this place for our rendezvous just for old times’ sake, you know.","TWN":"我之所以會把這裡當作再會的場所，不僅僅是因為回憶喔。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그만둬!!","JPN":"やめろ！！","ENG":"That’s enough!","TWN":"住手！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};